ee:message.ee:set-payload:
%dw 2.0
output text/plain

var pe = payload.event


// Placer ID (optional, SCH-1)
var placerId = if (pe.Placer_Appointment_ID__c == null or isEmpty(pe.Placer_Appointment_ID__c)) "" else (pe.Placer_Appointment_ID__c as String)
// Filler ID (required, SCH-2)
var fillerId = pe.NextGen_ID__c as String
var patientIdRaw = pe.Patient_ID__c as String
var patientLastName = pe.Patient_Last_Name__c as String
var patientFirstName = pe.Patient_First_Name__c as String
var patientDobRaw = pe.Patient_DOB__c as String
var patientGenderRaw = pe.Patient_Gender__c as String
var providerNpi = pe.Provider_NPI__c as String
var providerLast = pe.Provider_Last_Name__c as String
var providerFirst = pe.Provider_First_Name__c as String
var locationId = pe.Location_ID__c as String
var locationName = pe.Location_Name__c as String
var startDateTimeRaw = pe.Start_DateTime__c as String
var durationRaw = pe.Duration_Value__c as String
var statusRaw = pe.Appointment_Status__c as String
var apptType = pe.Appointment_Type__c as String

// Patient ID HL7
var pid =
  if ((patientIdRaw as String) startsWith "HF")
    (patientIdRaw as String)[2 to -1]
  else
    patientIdRaw as String

// DOB
var dob =
  (patientDobRaw as Date {format:"MMMM dd, yyyy"}) as String {format:"yyyyMMdd"}

// Gender HL7
var genderVal = upper(patientGenderRaw as String)
var gender =
  if (genderVal == "FEMALE") "F"
  else if (genderVal == "MALE") "M"
  else "U"

// Appointment
var startDT = (startDateTimeRaw as DateTime {format:"M/d/yyyy h:mm a"})
var schStartStr = (startDT as String {format:"yyyyMMddHHmmss"})
var duration = durationRaw as Number
var schEndDT = startDT + (duration * 60000)
var schEndStr = (schEndDT as DateTime) as String {format:"yyyyMMddHHmmss"}

// Phone (must be 10 digits)
var phone = pe.Patient_Phone__c as String
var phoneFormatted = if (sizeOf(phone) == 10) "(" ++ phone[0 to 2] ++ ")" ++ phone[3 to 5] ++ "-" ++ phone[6 to 9] else ""
var pid13 = phoneFormatted ++ "^^^^^" ++ phone[0 to 2] ++ "^" ++ phone[3 to 9]

var language = if (pe.Patient_Language__c == null or isEmpty(pe.Patient_Language__c)) "EN" else (pe.Patient_Language__c as String)
var reason = if (pe.Appointment_Reason__c == null) "" else pe.Appointment_Reason__c as String

var status =
  if (upper(statusRaw) == "SCHEDULED") "NEW"
  else if (upper(statusRaw) == "RESCHEDULED") "RESCHEDULED"
  else if (upper(statusRaw) == "CHECKED OUT") "CHECKED OUT"
  else if (upper(statusRaw) == "CHECKED IN") "CHECKED IN"
  else if (upper(statusRaw) == "CANCELLED BY PROVIDER") "CANCELLED"
  else if (upper(statusRaw) == "NO SHOW") "NO SHOW"
  else upper(statusRaw)

---
(
  "MSH|^~\\&|HEALTHFUSION^1266378|NEXTGENOFFICE^1266378|FORESTHMS|FORESTHMS^1266378|"
    ++ now() as String {format:"yyyyMMddHHmmss"}
    ++ "||SIU^S12|"
    ++ fillerId
    ++ "|P|2.3"
  ++ "\nSCH|" ++ placerId ++ "|" ++ fillerId ++ "||||" ++ apptType ++ "|" ++ reason ++ "|" ++ apptType ++ "|" ++ (durationRaw as String) ++ "|MIN|^^^" ++ schStartStr ++ "^" ++ schEndStr ++ "|||||" ++ providerNpi ++ "^" ++ upper(providerLast) ++ "^" ++ upper(providerFirst) ++ "|||||||||" ++ status
  ++ "\nPID|1|" ++ pid ++ "|" ++ pid ++ "|HF" ++ pid ++ "|" ++ upper(patientLastName) ++ "^" ++ upper(patientFirstName) ++ "|" ++ "|" ++ dob ++ "|" ++ gender ++ "|" ++ "|" ++ "PATIENT DECLINED|" ++ (pe.Patient_Street__c as String) ++ "^^" ++ (pe.Patient_City__c as String) ++ "^" ++ (pe.Patient_State__c as String) ++ "^" ++ (pe.Patient_Zip__c as String) ++ "|" ++ pid13 ++ "||" ++ language ++ "|||||||PATIENT DECLINED"
  ++ "\nPV1|1|O|^^^" ++ locationId ++ "^^^^^" ++ upper(locationName) ++ "||||" ++ providerNpi ++ "^" ++ upper(providerLast) ++ "^" ++ upper(providerFirst) ++ "||||" ++ "1275017^^^1275017^^^^^FOREST HILLS||||||||" ++ fillerId ++ "||||||||||||||||||||1266378;FOREST HILLS MEDICAL SERVICES;FORESTHMS|||||" ++ schStartStr ++ "|" ++ schEndStr
  ++ "\nRGS|"
  ++ "\nAIL|1||" ++ locationId ++ "^^^" ++ upper(locationName)
  ++ "\nAIP|1||" ++ providerNpi ++ "^" ++ upper(providerLast) ++ "^" ++ upper(providerFirst)
)

%dw 2.0
output text/plain

var pe = payload.event
var apptId = pe.NextGen_ID__c
var pid =
 if (pe.Patient_ID__c startsWith "HF") pe.Patient_ID__c[2 to -1]
 else pe.Patient_ID__c
var dob =
 if (pe.Patient_DOB__c != null)
   (pe.Patient_DOB__c as Date {format:"MMMM dd, yyyy"}) as String {format:"yyyyMMdd"}
 else
   ""
var gender =
 if (pe.Patient_Gender__c == "Female") "F"
 else if (pe.Patient_Gender__c == "Male") "M"
 else "U"
var phone = pe.Patient_Phone__c
var phone_formatted =
 if (sizeOf(phone) == 10)
   "(" ++ phone[0 to 2] ++ ")" ++ phone[3 to 5] ++ "-" ++ phone[6 to 9]
 else phone
var area = if (!isEmpty(phone) and sizeOf(phone)>=3) phone[0 to 2] else ""
var rest = if (!isEmpty(phone) and sizeOf(phone)>=7) phone[3 to 9] else ""
var contactInfo = phone_formatted ++ "^^^" ++ "^^" ++ area ++ "^" ++ rest
var status =
  if ((pe.Appointment_Status__c default "") as String == "Cancelled by Provider") "CANCELLED"
  else if ((pe.Appointment_Status__c default "") as String == "No Show") "NO SHOW"
  else if ((pe.Appointment_Status__c default "") as String == "RESCHEDULED") "RESCHEDULED"
  else if ((pe.Appointment_Status__c default "") as String == "Checked Out") "CHECKED OUT"
  else if ((pe.Appointment_Status__c default "") as String == "Checked In") "CHECKED IN"
  else if ((pe.Appointment_Status__c default "") as String == "Scheduled") "NEW"
  else upper(pe.Appointment_Status__c default "")

var schStart =
  if ((pe.Start_DateTime__c default "") != "")
    (pe.Start_DateTime__c as DateTime {format:"M/d/yyyy h:mm a"})
  else null
var schStartStr =
  if (schStart != null) (schStart as String {format:"yyyyMMddHHmmss"}) else ""
var schEnd =
  if ((pe.Duration_Value__c default "") != "" and schStart != null)
    schStart + ((pe.Duration_Value__c as Number) * 60000)
  else schStart
var schEndStr =
  if (schEnd != null) (schEnd as String {format:"yyyyMMddHHmmss"}) else ""

var providerNpi = pe.Provider_NPI__c default ""
var providerLast = upper(pe.Provider_Last_Name__c default "")
var providerFirst = upper(pe.Provider_First_Name__c default "")
var apptType = upper(pe.Appointment_Type__c default "")
var apptReason = if ((pe.Appointment_Reason__c default "") != "") pe.Appointment_Reason__c else ""
var locationId = pe.Location_ID__c default ""
var locationName = upper(pe.Location_Name__c default "")
var patientLast = upper(pe.Patient_Last_Name__c default "")
var patientFirst = upper(pe.Patient_First_Name__c default "")
var language = upper(pe.Patient_Language__c default "EN")
var patientStreet = upper(pe.Patient_Street__c default "")
var patientCity = upper(pe.Patient_City__c default "")
var patientState = upper(pe.Patient_State__c default "")
var patientZip = upper(pe.Patient_Zip__c default "")

---
(
"MSH|^~\\&|HEALTHFUSION^1266378|NEXTGENOFFICE^1266378|FORESTHMS|FORESTHMS^1266378|" ++ now() as String {format:"yyyyMMddHHmmss"} ++ "||SIU^S15|" ++ (apptId default "") ++ "|P|2.3"
++ "\nSCH||" ++ (apptId default "") ++ "||||" ++ apptType ++ "|" ++ apptReason ++ "|" ++ apptType ++ "|" ++ (pe.Duration_Value__c default "") ++ "|MIN|" ++ "^^^" ++ schStartStr ++ "^" ++ schEndStr ++ "|||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "|||||||||" ++ status
++ "\nPID|1|" ++ pid ++ "|" ++ pid ++ "|HF" ++ pid ++ "|" ++ patientLast ++ "^" ++ patientFirst ++ "|" ++ "|" ++ dob ++ "|" ++ gender ++ "|" ++ "|" ++ "PATIENT DECLINED|" ++ patientStreet ++ "^^" ++ patientCity ++ "^" ++ patientState ++ "^" ++ patientZip ++ "|" ++ contactInfo ++ "||" ++ language ++ "|||||||PATIENT DECLINED"
++ "\nPV1|1|O|^^^" ++ locationId ++ "^^^^^" ++ locationName ++ "||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "||||1275017^^^1275017^^^^^FOREST HILLS||||||||" ++ (apptId default "") ++ "||||||||||||||||||||1266378;FOREST HILLS MEDICAL SERVICES;FORESTHMS|||||" ++ schStartStr ++ "|" ++ schEndStr
++ "\nRGS|"
++ "\nAIL|1||" ++ locationId ++ "^^^" ++ locationName
++ "\nAIP|1||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst
)
